"import asyncio\nimport certifi\nfrom motor.motor_asyncio import AsyncIOMotorClient\nfrom pymongo import MongoClient\nimport os\n\n# Let's test standard motor URIs\nuris = [\n    # Original without ssl=true\n    'mongodb://meddynetlabs_db_user:Mz4v4uyaAaRiP0Ig@ac-pzspd9o-shard-00-00.6lzhtrl.mongodb.net:27017,ac-pzspd9o-shard-00-01.6lzhtrl.mongodb.net:27017,ac-pzspd9o-shard-00-02.6lzhtrl.mongodb.net:27017/meddynet_analytics?replicaSet=atlas-pzspd9o-shard-0&authSource=admin&retryWrites=true&w=majority',\n    # SRV with cluster0\n    'mongodb+srv://meddynetlabs_db_user:Mz4v4uyaAaRiP0Ig@cluster0.6lzhtrl.mongodb.net/meddynet_analytics?retryWrites=true&w=majority',\n    # SRV without cluster0 (sometimes Atlas uses the hash prefix directly)\n    'mongodb+srv://meddynetlabs_db_user:Mz4v4uyaAaRiP0Ig@pzspd9o.6lzhtrl.mongodb.net/meddynet_analytics?retryWrites=true&w=majority',\n    # SRV with atlas-pzspd9o\n    'mongodb+srv://meddynetlabs_db_user:Mz4v4uyaAaRiP0Ig@atlas-pzspd9o.6lzhtrl.mongodb.net/meddynet_analytics?retryWrites=true&w=majority'\n]\n\ndef test_uris():\n    results = []\n    for idx, uri in enumerate(uris):\n        try:\n            client = MongoClient(uri, tls=True, tlsCAFile=certifi.where(), tlsAllowInvalidCertificates=True, serverSelectionTimeoutMS=5000)\n            client.admin.command('ping')\n            results.append(f'[{idx}] SUCCESS: {uri[:40]}...')\n        except Exception as e:\n            results.append(f'[{idx}] FAILED: {uri[:40]}... -> {e}')\n    \n    with open('scripts/uri_test_results.txt', 'w', encoding='utf-8') as f:\n        for r in results:\n            f.write(r + '\\n')\n\nif __name__ == '__main__':\n    test_uris()\n"
